  ('real-estate-moex-02535', 'real-estate', 'real-estate-moex-097-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '比較標的因極老舊，使其較一般正常價格低 8%，而勘估標的裝潢特佳，此一因素使其較正常價格高 5%。 若勘估標的與比較標的之其餘各項條件都相同，且已知比較標的之成交價為 500 萬元，則勘估標的之正常 價格為何？', '["570.65萬元", "438.10萬元", "483.00萬元", "485.00萬元"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "4cfaff7ead36", "answer_pdf_sha1": "e65526dd9c9f", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "601", "s": "3001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02536', 'real-estate', 'real-estate-moex-097-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '以比較標的之價格為基礎，就比較標的與勘估標的因個別因素所產生價格差異，逐項進行之分析及調整， 此種調整稱為：', '["情況調整", "價格日期調整", "區域因素調整", "個別因素調整"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "4cfaff7ead36", "answer_pdf_sha1": "e65526dd9c9f", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "601", "s": "3001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02537', 'real-estate', 'real-estate-moex-097-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '有關比較、分析勘估標的與比較標的之區域因素及個別因素差異，並就其中差異進行價格調整時，下列敘 述何者正確？', '["其調整以比較法為原則，並得以計量模型分析法調整", "其調整以差額法為原則，並得以百分率法調整", "其調整以百分率法為原則，並得以差額法調整", "其調整以百分率法為原則，並得以比較法調整"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "4cfaff7ead36", "answer_pdf_sha1": "e65526dd9c9f", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "601", "s": "3001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02538', 'real-estate', 'real-estate-moex-097-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '大甲建設公司擬投資某一建地興建住宅，預估營建完成後之總銷售金額為 264 億元；若開發總直接成本為 100億元，總間接成本為20億元，整個投資案的要求利潤率為20%。今假設開發所需總成本之資本利息綜 合利率為10%，請問取得該建地之土地開發分析價格為何？', '["80億元", "90.91億元", "109.09億元", "110億元"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "4cfaff7ead36", "answer_pdf_sha1": "e65526dd9c9f", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "601", "s": "3001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02539', 'real-estate', 'real-estate-moex-097-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '某建物樓地板面積共100坪，重新建造每坪花費5萬元，若依經濟耐用年數提列折舊，經濟耐用年數為50 年，殘值率為20%，目前已使用10年，若採定額法折舊，請問其平均每年折舊率為何？', '["2.4%", "2.0%", "1.6%", "0.4%"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "4cfaff7ead36", "answer_pdf_sha1": "e65526dd9c9f", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "601", "s": "3001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02540', 'real-estate', 'real-estate-moex-097-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '某建物之重建成本為200萬元，若第二年的價格為第一年價格的98%，第三年的價格亦為第二年價格的98%， 依此方式類推而折舊（定率法），請問經過10年後建物價格變成多少元？', '["166.75萬元", "163.41萬元", "160.15萬元", "160.00萬元"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "4cfaff7ead36", "answer_pdf_sha1": "e65526dd9c9f", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "601", "s": "3001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02541', 'real-estate', 'real-estate-moex-097-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '勘估標的為建物時，規劃設計費除可按內政部所定建築師酬金標準表及直轄市或縣（市）政府發布之建造 執照工程造價表計算外，亦可按實際營造施工費用之多少比例推估之？', '["百分之二至百分之三", "百分之三至百分之四", "百分之四至百分之五", "百分之五至百分之六"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "4cfaff7ead36", "answer_pdf_sha1": "e65526dd9c9f", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "601", "s": "3001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
